import { $Browser } from '../browser-detect';
import { d3_zc as d3, d3_event } from '../d3-constants';
import { getTranslationFromOwnerSVGElement } from '../../utils/svg-transforms';

export function d3_mouse(_node, event) {
    let node = _node;
    if (node.isD3Selection) {
        node = node.node();
    }

    event = event || d3_event();
    // event = event?.changedTouches?.[0] || event;

    // do firefox check only with svg elements
    if ((($Browser.FIREFOX || $Browser.SAFARI) && (node.ownerSVGElement || node instanceof SVGElement)) || event?.customListenedEvent) {
        // Firefox getScreenCTM() issue
        // getScreenCTM() doesn't work correctly with parent container positioned with transform:translate
        // https://bugzilla.mozilla.org/show_bug.cgi?id=972041
        // http://bl.ocks.org/mwdchang/raw/a88aa3f61f5a2243d15bb8a264aa432e/
        // https://github.com/d3/d3/issues/2771

        // Since d3.mouse is not working properly, using fallback getBoundingClientRect

        let svg = node.ownerSVGElement || node;

        let source,
            rect = svg.getBoundingClientRect();
        while ((source = event.sourceEvent)) {
            event = source;
        }
        if (event.changedTouches) {
            event = event.changedTouches[0];
        }

        let [translateX, translateY] = getTranslationFromOwnerSVGElement(node);

        translateX = event.clientX - rect.left - node.clientLeft - translateX;
        translateY = event.clientY - rect.top - node.clientTop - translateY;

        return [translateX, translateY];
    } else {
        return d3.pointer.apply(this || window, [event?.changedTouches?.[0] || event, node]);
    }
}
